export function IcoJunctionAnalytics() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* 4-way intersection */}
      <line x1="100" y1="8" x2="100" y2="122" stroke={palette.mid} strokeWidth="14" opacity="0.30" />
      <line x1="8" y1="65" x2="192" y2="65" stroke={palette.mid} strokeWidth="14" opacity="0.30" />
      {/* Colored flow arrows at each approach */}
      {/* Top approach → down */}
      <polygon points="100,20 92,38 108,38" fill="#4caf50" />
      {/* Bottom approach → up */}
      <polygon points="100,110 92,92 108,92" fill={palette.accent} />
      {/* Left → right */}
      <polygon points="20,65 38,57 38,73" fill={palette.accent} />
      {/* Right → left */}
      <polygon points="180,65 162,57 162,73" fill="#e53935" />
    </svg>
  );
}
